const s3Data = $input.first().json;
const dadosLote = $('Validar e Preparar Dados').first().json;

let todosResultados = [];
try {
  todosResultados = $('Processar e Calcular').all();
} catch (error) {
  todosResultados = [];
}

const valorTotal = todosResultados.reduce((sum, item) => sum + (Number(item.json.valor) || 0), 0);
const creditoTotal = todosResultados.reduce((sum, item) => sum + (Number(item.json.credito) || 0), 0);

let pdfUrl = null;
try {
  const pdfUpload = $('Upload PDF para S').first().json;
  pdfUrl = pdfUpload.Location || pdfUpload.location || null;
} catch (error) {
  pdfUrl = null;
}

const downloadUrl = s3Data.s3_location_real || s3Data.s3_location;
const excelFilename = s3Data.excel_filename || `holerite_lote_${dadosLote.total_arquivos}competencias.xlsx`;

// Pega competência do primeiro arquivo para manter compatibilidade com campos antigos
const primeiroArquivo = dadosLote.arquivos ? dadosLote.arquivos[0] : null;
const competenciaLegacy = primeiroArquivo ? primeiroArquivo.competencia : (dadosLote.competencia || '');
const fileIdLegacy = primeiroArquivo ? primeiroArquivo.file_id : (dadosLote.file_id || '');

const response = {
  // Campos de status
  success: true,
  ok: true,
  completed: true,
  status: 'completed',
  message: `Processamento em lote concluído: ${dadosLote.total_arquivos} competência(s) processada(s)`,

  // Campos de identificação — mantidos para compatibilidade com front-end
  processing_id: s3Data.processing_id || dadosLote.processing_id,
  file_id: s3Data.file_id || fileIdLegacy,

  // Campos de arquivo — TODOS os formatos de nome/url que o front-end pode usar
  filename: excelFilename,
  excel_filename: excelFilename,
  nome_arquivo: excelFilename,
  mime_type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  content_type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',

  // URLs de download — TODOS os campos possíveis para garantir compatibilidade
  download_url: downloadUrl,
  url: downloadUrl,
  excel_url: downloadUrl,
  file_url: downloadUrl,
  fileUrl: downloadUrl,
  downloadUrl: downloadUrl,
  link: downloadUrl,
  href: downloadUrl,

  // Objeto data completo — mantém estrutura original + campos novos de lote
  data: {
    processing_id: s3Data.processing_id || dadosLote.processing_id,

    // Campos legados (arquivo único) — mantidos para compatibilidade
    competencia: competenciaLegacy,
    file_id: fileIdLegacy,
    processado_em: new Date().toISOString(),

    // Campos novos de lote
    total_arquivos: dadosLote.total_arquivos,
    competencias: dadosLote.arquivos ? dadosLote.arquivos.map(a => a.competencia) : [competenciaLegacy],

    arquivo: {
      // Campos legados
      file_id: fileIdLegacy,
      filename: excelFilename,
      excel_filename: excelFilename,
      status: 'success',

      // URLs em todos os formatos possíveis
      url: downloadUrl,
      excel_url: downloadUrl,
      download_url: downloadUrl,
      file_url: downloadUrl,
      fileUrl: downloadUrl,
      downloadUrl: downloadUrl,
      link: downloadUrl,
      href: downloadUrl,

      mime_type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',

      // Objeto urls aninhado (existia no original)
      urls: {
        pdf: pdfUrl,
        excel: downloadUrl,
        excel_download: downloadUrl,
        download: downloadUrl
      }
    },

    resumo: {
      total_proventos: todosResultados.length,
      total_rubricas: todosResultados.length,
      valor_total: parseFloat(valorTotal.toFixed(2)),
      credito_total: parseFloat(creditoTotal.toFixed(2))
    }
  }
};

try {
  const staticData = $getWorkflowStaticData('global');
  const key = `processing_${dadosLote.processing_id}`;
  staticData[key] = { status: 'completed', createdAt: Date.now(), response };
} catch (error) {}

return [{ json: response }];

const uploadResult = $input.first().json;
const metadados = $('Adicionar Metadados ao XLSX').first().json;

if (!uploadResult.ETag && !uploadResult.Location) {
  throw new Error('Upload para S3 falhou - sem ETag ou Location retornado');
}

return [{
  json: {
    ...metadados,
    upload_success: true,
    uploaded_at: new Date().toISOString(),
    s3_etag: uploadResult.ETag,
    s3_location_real: uploadResult.Location
  }
}];

// ✅ AJUSTE 3+4: Nome do arquivo reflete o lote
const xlsxItem = $input.first();
const dadosLote = $('Validar e Preparar Dados').first().json;

const totalArquivos = dadosLote.total_arquivos || 1;
const companyNameLimpo = (dadosLote.company_name || 'empresa').replace(/[^a-zA-Z0-9\s]/g, '').trim();

// Nome do arquivo consolidado com todas as competências
const competencias = dadosLote.arquivos
  ? dadosLote.arquivos.map(a => a.competencia.replace('/', '_')).join('-')
  : 'lote';

const nomeArquivoLimpo = `holerite_lote_${competencias}_${companyNameLimpo}.xlsx`;

const bucket = 'e7pdf-holerite';
const region = 'sa-east-1';
const s3Key = `e7-holerite/${companyNameLimpo.replace(/\s/g, '_').toLowerCase()}/lote/${competencias}/extracao_excel/${nomeArquivoLimpo}`;

const binaryData = xlsxItem.binary;
const binaryKey = Object.keys(binaryData)[0];
const updatedBinary = {};
updatedBinary[binaryKey] = {
  ...binaryData[binaryKey],
  fileName: nomeArquivoLimpo
};

return [{
  json: {
    company_name: dadosLote.company_name,
    company_cnpj: dadosLote.company_cnpj,
    company_id: dadosLote.company_id,
    total_arquivos: totalArquivos,
    competencias: dadosLote.arquivos ? dadosLote.arquivos.map(a => a.competencia) : [],
    processing_id: dadosLote.processing_id,
    timestamp: new Date().toISOString(),
    s3_bucket: bucket,
    s3_region: region,
    s3_key: s3Key,
    s3_location: `https://${bucket}.s3.${region}.amazonaws.com/${encodeURIComponent(s3Key).replace(/%2F/g, '/')}`,
    excel_filename: nomeArquivoLimpo
  },
  binary: updatedBinary
}];

// ✅ AJUSTE 1: SELIC zerada (coluna mantida, sem preenchimento automático)
// ✅ AJUSTE 4: Consolidar todos os itens de todos os arquivos e ordenar por competência

const items = $input.all();

if (!items || items.length === 0) {
  throw new Error('Nenhum dado para consolidar');
}

const todasLinhas = items.map(item => {
  const data = item.json;
  return {
    'COD': data.cod,
    'Nome Rubrica': data.nome_rubrica,
    'Valor': data.valor,
    'Contribuição': data.contribuicao,
    'RAT': data.rat + '%',
    'VL RAT AJUSTADO': data.vl_rat_ajustado,
    'TERCEIROS 5,8': data.terceiros + '%',
    'VL CONT TERCEIROS': data.vl_cont_terceiros,
    'TOTAL': data.total,
    // ✅ SELIC: coluna mantida, vazia para preenchimento manual
    'SELIC': '',
    'VL SELIC': '',
    'Crédito': data.credito,
    // ✅ Período como MM/AAAA
    'Período': data.periodo,
    'CNPJ': data.cnpj,
    _mes: parseInt((data.periodo || '').split('/')[0] || 0),
    _ano: parseInt((data.periodo || '').split('/')[1] || 0)
  };
});

// ✅ AJUSTE 4: Ordena por competência (mais antigo → mais novo)
todasLinhas.sort((a, b) => {
  if (a._ano !== b._ano) return a._ano - b._ano;
  return a._mes - b._mes;
});

// Remove campos auxiliares de ordenação
const linhasLimpas = todasLinhas.map(({ _mes, _ano, ...resto }) => resto);

// Agrupa por período para subtotais
const porPeriodo = {};
for (const linha of linhasLimpas) {
  const p = linha['Período'] || 'SEM_PERIODO';
  if (!porPeriodo[p]) porPeriodo[p] = [];
  porPeriodo[p].push(linha);
}

// Monta resultado final com subtotais por competência
const resultado = [];
const periodosOrdenados = Object.keys(porPeriodo).sort((a, b) => {
  const [ma, aa] = a.split('/').map(Number);
  const [mb, ab] = b.split('/').map(Number);
  return aa !== ab ? aa - ab : ma - mb;
});

for (const periodo of periodosOrdenados) {
  const grupo = porPeriodo[periodo];
  resultado.push(...grupo);

  // Linha de subtotal por competência
  resultado.push({
    'COD': `SUBTOTAL ${periodo}`,
    'Nome Rubrica': '',
    'Valor': grupo.reduce((s, r) => s + (parseFloat(r['Valor']) || 0), 0),
    'Contribuição': grupo.reduce((s, r) => s + (parseFloat(r['Contribuição']) || 0), 0),
    'RAT': '',
    'VL RAT AJUSTADO': grupo.reduce((s, r) => s + (parseFloat(r['VL RAT AJUSTADO']) || 0), 0),
    'TERCEIROS 5,8': '',
    'VL CONT TERCEIROS': grupo.reduce((s, r) => s + (parseFloat(r['VL CONT TERCEIROS']) || 0), 0),
    'TOTAL': grupo.reduce((s, r) => s + (parseFloat(r['TOTAL']) || 0), 0),
    'SELIC': '',
    'VL SELIC': '',
    'Crédito': grupo.reduce((s, r) => s + (parseFloat(r['Crédito']) || 0), 0),
    'Período': periodo,
    'CNPJ': ''
  });
}

// Linha de total geral
resultado.push({
  'COD': 'TOTAL GERAL',
  'Nome Rubrica': '',
  'Valor': linhasLimpas.reduce((s, r) => s + (parseFloat(r['Valor']) || 0), 0),
  'Contribuição': linhasLimpas.reduce((s, r) => s + (parseFloat(r['Contribuição']) || 0), 0),
  'RAT': '',
  'VL RAT AJUSTADO': linhasLimpas.reduce((s, r) => s + (parseFloat(r['VL RAT AJUSTADO']) || 0), 0),
  'TERCEIROS 5,8': '',
  'VL CONT TERCEIROS': linhasLimpas.reduce((s, r) => s + (parseFloat(r['VL CONT TERCEIROS']) || 0), 0),
  'TOTAL': linhasLimpas.reduce((s, r) => s + (parseFloat(r['TOTAL']) || 0), 0),
  'SELIC': '',
  'VL SELIC': '',
  'Crédito': linhasLimpas.reduce((s, r) => s + (parseFloat(r['Crédito']) || 0), 0),
  'Período': '',
  'CNPJ': ''
});

return resultado.map((row, index) => ({ json: row, pairedItem: index }));

// SELIC zerada; período MM/AAAA por arquivo do lote (não só .first())

const inputItems = $input.all();
if (!inputItems || inputItems.length === 0) {
  throw new Error('Nenhuma saída do AI Agent recebida');
}

const metadadosPorArquivo = $('Validar e Preparar Dados').all().map(i => i.json);

function parseOutput(output) {
  if (!output) return null;
  try {
    if (typeof output === 'string') {
      const clean = output.replace(/```json/g, '').replace(/```/g, '').trim();
      const start = clean.indexOf('{');
      const end = clean.lastIndexOf('}');
      if (start >= 0 && end >= 0) return JSON.parse(clean.slice(start, end + 1));
      return JSON.parse(clean);
    }
    return output;
  } catch (e) {
    return null;
  }
}

function isResumoOuBase(prov) {
  const codigo = String(prov.codigo || prov.cod || '').toUpperCase();
  const nome = String(prov.nome || prov.nome_rubrica || '')
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase();
  return codigo.includes('SALARIO_CONTRIB') ||
    nome.includes('SALARIO CONTRIBUICAO') ||
    nome.includes('SALARIO DE CONTRIBUICAO') ||
    nome.includes('CONTRIBUICAO EMPREGADOS') ||
    nome.includes('CONTRIBUICAO CONTRIBUINTES');
}

const RAT = 2.00;
const TERCEIROS = 5.80;
const vistos = new Set();
const saida = [];

for (let idx = 0; idx < inputItems.length; idx++) {
  const item = inputItems[idx];
  const parsed = parseOutput(item.json.output);
  if (!parsed || !Array.isArray(parsed.proventos)) continue;

  const meta = metadadosPorArquivo[idx] || metadadosPorArquivo[0] || {};
  const competenciaArquivo =
    parsed.competencia ||
    meta.competencia ||
    (Array.isArray(meta.arquivos) && meta.arquivos[idx] ? meta.arquivos[idx].competencia : '') ||
    '';

  const empresaNome =
    (typeof parsed.empresa === 'string' ? parsed.empresa : (parsed.empresa?.nome || '')) ||
    meta.company_name ||
    '';
  const cnpjEmpresa =
    parsed.cnpj ||
    (typeof parsed.empresa === 'object' ? parsed.empresa?.cnpj : '') ||
    meta.company_cnpj ||
    '';

  for (const prov of parsed.proventos) {
    if (!prov || isResumoOuBase(prov)) continue;

    const codigo = String(prov.codigo || prov.cod || '').trim();
    const nome = String(prov.nome || prov.nome_rubrica || '').trim();

    let valor = 0;
    if (typeof prov.valor === 'number') {
      valor = prov.valor;
    } else {
      const raw = String(prov.valor ?? '').trim();
      valor = raw.includes(',')
        ? parseFloat(raw.replace(/\./g, '').replace(',', '.')) || 0
        : parseFloat(raw) || 0;
    }

    const chave = `${competenciaArquivo}|${codigo}|${nome}|${valor.toFixed(2)}`;
    if (vistos.has(chave)) continue;
    vistos.add(chave);

    const contribuicao = valor * (RAT / 100);
    const vl_rat_ajustado = contribuicao * (RAT / 100);
    const vl_cont_terceiros = valor * (TERCEIROS / 100);
    const total = contribuicao + vl_rat_ajustado + vl_cont_terceiros;

    saida.push({ json: {
      cod: codigo,
      nome_rubrica: nome,
      valor,
      contribuicao: parseFloat(contribuicao.toFixed(2)),
      rat: RAT,
      vl_rat_ajustado: parseFloat(vl_rat_ajustado.toFixed(2)),
      terceiros: TERCEIROS,
      vl_cont_terceiros: parseFloat(vl_cont_terceiros.toFixed(2)),
      total: parseFloat(total.toFixed(2)),
      selic: '',
      vl_selic: '',
      credito: parseFloat(total.toFixed(2)),
      periodo: competenciaArquivo,
      cnpj: cnpjEmpresa,
      empresa_nome: empresaNome,
      competencia: competenciaArquivo,
      tipo_mapeado: prov.categoria || prov.tipo_mapeado || 'OUTROS',
      file_id: meta.file_id,
      processing_id: meta.processing_id
    }});
  }
}

if (saida.length === 0) throw new Error('Nenhum provento foi extraído pelo AI Agent');

return saida;

const out = [];
for (const item of $input.all()) {
  const data = item.json || {};
  const partes = [];
  if (Array.isArray(data.pages) && data.pages.length > 0) {
    for (const pg of data.pages) {
      if (typeof pg === 'string') partes.push(pg);
      else if (pg && typeof pg === 'object') partes.push(pg.markdown || pg.text || pg.content || JSON.stringify(pg));
      else if (pg !== undefined && pg !== null) partes.push(String(pg));
    }
  } else {
    partes.push(data.text || data.markdown || data.content || data.data || '');
  }
  const texto = partes.filter(Boolean).map(v => String(v).trim()).filter(Boolean).join('\n\n--- QUEBRA DE PÁGINA ---\n\n');
  if (!texto) throw new Error('Nenhum texto extraído para enviar ao modelo');
  out.push({ json: { chatInput: texto, totalCaracteres: texto.length, totalPartes: partes.filter(Boolean).length } });
}
return out;

// ✅ AJUSTE 3: Validar e Preparar Dados — suporte a lote de até 12 arquivos
// Cada arquivo tem sua própria competência

const items = $input.all();
const item = items[0];
const body = item.json.body || item.json;

// Suporte tanto ao formato antigo (um arquivo) quanto ao novo (array de arquivos)
let arquivosRaw = [];

if (Array.isArray(body.arquivos) && body.arquivos.length > 0) {
  // Novo formato: { arquivos: [{ pdf_base64, competencia, file_id, filename }] }
  arquivosRaw = body.arquivos;
} else if (Array.isArray(body.files) && body.files.length > 0) {
  // Compatibilidade com formato anterior
  arquivosRaw = body.files.map(f => ({
    pdf_base64: f.pdf_base64,
    competencia: body.competency || body.competencia,
    file_id: f.file_id,
    filename: f.filename
  }));
} else if (body.pdf || body.pdf_base64) {
  // Compatibilidade com envio de arquivo único
  arquivosRaw = [{
    pdf_base64: body.pdf || body.pdf_base64,
    competencia: body.competency || body.competencia,
    file_id: body.file_id,
    filename: body.filename
  }];
} else {
  throw new Error('Nenhum arquivo encontrado. Envie via campo "arquivos" (array), "files" (array) ou "pdf" (único).');
}

if (arquivosRaw.length === 0) throw new Error('Nenhum arquivo recebido');
if (arquivosRaw.length > 12) throw new Error(`Máximo de 12 arquivos por requisição. Recebidos: ${arquivosRaw.length}`);

const processing_id = body.processing_id || `proc_${Date.now()}`;
const companyData = body.company_data || {};
const company_name = body.company_name || companyData.name || 'Empresa';
const company_cnpj = body.company_cnpj || companyData.cnpj || '';
const company_id = body.company_id || '';

// Valida e prepara cada arquivo
const arquivosPreparados = arquivosRaw.map((arq, idx) => {
  if (!arq.pdf_base64) throw new Error(`Arquivo ${idx + 1} não contém campo 'pdf_base64'`);

  const competenciaRaw = arq.competencia || body.competency || body.competencia || '';
  if (!competenciaRaw) throw new Error(`Arquivo ${idx + 1} não tem competência definida`);

  const partes = competenciaRaw.toString().split('/');
  if (partes.length !== 2) throw new Error(`Competência inválida no arquivo ${idx + 1}: use MM/AAAA. Recebido: ${competenciaRaw}`);

  const mes = partes[0].padStart(2, '0');
  const ano = partes[1];
  const competencia = `${mes}/${ano}`;

  const pdfBuffer = Buffer.from(arq.pdf_base64, 'base64');
  const fileId = arq.file_id || `file_${idx + 1}_${Date.now()}`;
  const filename = arq.filename || `holerite_${competencia.replace('/', '_')}_${idx + 1}.pdf`;

  return {
    competencia,
    mes,
    ano,
    file_id: fileId,
    nomeArquivo: filename,
    pdfBuffer,
    pdf_base64: arq.pdf_base64
  };
});

// ✅ AJUSTE 4: Ordena por competência antes mesmo de processar (mais antigo → mais novo)
arquivosPreparados.sort((a, b) => {
  if (a.ano !== b.ano) return parseInt(a.ano) - parseInt(b.ano);
  return parseInt(a.mes) - parseInt(b.mes);
});

// Emite um item por arquivo para processar individualmente
return arquivosPreparados.map((arq, idx) => ({
  json: {
    competencia: arq.competencia,
    mes: arq.mes,
    ano: arq.ano,
    company_id,
    company_name,
    company_cnpj,
    file_id: arq.file_id,
    nomeArquivo: arq.nomeArquivo,
    processing_id,
    indice: idx,
    total_arquivos: arquivosPreparados.length,
    arquivos: arquivosPreparados.map(a => ({ competencia: a.competencia, file_id: a.file_id, nomeArquivo: a.nomeArquivo })),
    timestamp: new Date().toISOString(),
    ...(body.user_id && { user_id: body.user_id }),
    ...(body.session_id && { session_id: body.session_id })
  },
  binary: {
    pdf: {
      data: arq.pdfBuffer,
      mimeType: 'application/pdf',
      fileName: arq.nomeArquivo,
      fileExtension: 'pdf'
    }
  }
}));

const staticData = $getWorkflowStaticData('global');
const now = Date.now();
const ttlMs = 30 * 60 * 1000;
for (const [k, v] of Object.entries(staticData)) {
  if (k.startsWith('processing_') && v?.createdAt && now - v.createdAt > ttlMs) {
    delete staticData[k];
  }
}
const out = [];
for (const item of $input.all()) {
  const data = item.json || {};
  if (!data.processing_id) throw new Error('processing_id ausente');
  const fileKey = data.file_id || data.nomeArquivo || 'arquivo';
  const key = `processing_${data.processing_id}_${fileKey}`;
  if (staticData[key]) {
    out.push({ json: { ...data, duplicate_execution: true, previous_status: staticData[key].status, previous_created_at: staticData[key].createdAt, cached_response: staticData[key].response || null }, binary: item.binary });
    continue;
  }
  staticData[key] = { status: 'processing', createdAt: now };
  out.push({ json: { ...data, duplicate_execution: false, dedup_key: key }, binary: item.binary });
}
return out;

parameters.responseBody:
={{ $json.cached_response || {
  "success": false,
  "duplicate": true,
  "status": $json.previous_status || "processing",
  "message": "Este processamento já está em andamento",
  "data": {
    "processing_id": $json.processing_id,
    "file_id": $json.file_id,
    "previous_created_at": $json.previous_created_at
  }
} }}
